const url = 'http://localhost:6006/iframe.html?id=player-playerprofile--primary&viewMode=story';
const browser = await chromium.launch();
const page = await browser.newPage();

async function measure(width) {
    await page.setViewportSize({ width, height: 900 });
    await page.goto(url, { waitUntil: 'networkidle' });
    // Wait for the four cards to render
    await page.waitForSelector('text=Info');
    const boxes = await page.evaluate(() => {
        // Find the Paper elements for the four cards by their distinguishing text
        const findCardRect = (label) => {
            const el = [...document.querySelectorAll('*')].find(e => e.textContent.trim() === label && e.tagName === 'H3');
            if (!el) return null;
            let node = el;
            // climb to the DebugSizeOverlay wrapper (has a badge with px measurements)
            while (node && !node.querySelector('.mantine-Badge-root')) node = node.parentElement;
            const rect = node.getBoundingClientRect();
            return { top: rect.top, left: rect.left, right: rect.right, width: rect.width };
        };
        return {
            info: findCardRect('Info'),
            results: findCardRect('Results'),
            positions: findCardRect('Positions'),
        };
    });
    console.log(`viewport=${width}px`, JSON.stringify(boxes));
}

for (const w of [1400, 900, 700, 500, 380]) {
    await measure(w);
}

await browser.close();
