    const h3s = [...document.querySelectorAll('h3')].map(h => h.textContent.trim());
    // find the Group container (parent of the 4 card wrappers)
    const infoTitle = [...document.querySelectorAll('h3')].find(h => h.textContent.trim() === 'Info');
    let node = infoTitle;
    const chain = [];
    for (let i = 0; i < 8 && node; i++) {
        const cs = getComputedStyle(node);
        chain.push({
            tag: node.tagName,
            cls: node.className && node.className.toString().slice(0, 60),
            display: cs.display,
            flex: cs.flex,
            flexWrap: cs.flexWrap,
            width: node.getBoundingClientRect().width,
        });
        node = node.parentElement;
    }
    return { h3s, chain };
});
console.log(JSON.stringify(info, null, 2));
await browser.close();
