    const next = document.querySelector('[data-testid="player-next-placeholder"]');
    const title = document.querySelector('h1');
    return {
        prevSlot: prev.parentElement.getBoundingClientRect(),
        nextSlot: next.parentElement.getBoundingClientRect(),
        titleCenter: title.getBoundingClientRect().left + title.getBoundingClientRect().width / 2,
    };
});

// Simulate an asymmetric nav link: give the left slot real (wider) content, leave right slot empty
