    const prev = document.querySelector('[data-testid="player-prev-placeholder"]');
    prev.outerHTML = '<a href="#" style="white-space:nowrap">&larr; Some Fairly Long Player Name</a>';
    const prevSlotEl = document.querySelector('a[href="#"]').parentElement;
    const next = document.querySelector('[data-testid="player-next-placeholder"]');
