    return {
        prevSlot: prevSlotEl.getBoundingClientRect(),
        nextSlot: next.parentElement.getBoundingClientRect(),
        titleCenter: title.getBoundingClientRect().left + title.getBoundingClientRect().width / 2,
    };
});

